from typing import List

class Solution:
    def find(self, s: str, k: int, m: int) -> int:
        n = len(s)
        dp = [[-1 for _ in range(k + m + 1)] for _ in range(n + 1)]
        for i in range(n + 1):
            for j in range(k + m + 1):
                if i == 0:
                    dp[i][j] = 0
                elif j == 0:
                    dp[i][j] = i
                elif s[i-1] == s[i-2]:
                    dp[i][j] = dp[i-1][j]
                else:
                    dp[i][j] = 1 + min(dp[i-1][j-1], dp[i-1][j-2], dp[i-2][j-1])
        return dp[n][k + m]

if __name__ == '__main__':
    s = input()
    k, m = map(int, input().split())
    print(Solution().find(s, k, m))
